#include <stdio.h>
#include <math.h>
#include <stdlib.h>

// Structure to hold processor specifications
typedef struct {
 char name[50];
 double frequency_hz;
 double cpi;
 long instruction_count;
} Processor;

// Calculate clock period in nanoseconds
double calculate_clock_period_ns(double frequency_hz) {
 // T = 1 / f, convert to nanoseconds
 return (1.0 / frequency_hz) * 1e9;
}

// Calculate CPU time in milliseconds
double calculate_cpu_time_ms(long instruction_count, double cpi, double frequency_hz) {
 double clock_period = 1.0 / frequency_hz;
 double total_cycles = (double)instruction_count * cpi;
 return total_cycles * clock_period * 1000.0; // Convert to ms
}

// Calculate total clock cycles
long double calculate_total_cycles(long instruction_count, double cpi) {
 return (long double)instruction_count * cpi;
}

// Simulate clock skew impact
void analyze_clock_skew(double frequency_ghz, double wire_delay_ns) {
 double period_ns = 1000.0 / frequency_ghz; // Convert GHz to ns period

 printf("\n--- Clock Skew Analysis ---\n");
 printf("Clock Frequency: %.2f GHz\n", frequency_ghz);
 printf("Clock Period: %.3f ns\n", period_ns);
 printf("Wire Delay: %.3f ns\n", wire_delay_ns);
 printf("Skew as %% of Period: %.2f%%\n", (wire_delay_ns / period_ns) * 100);

 if (wire_delay_ns >= period_ns * 0.1) {
 printf("WARNING: Clock skew exceeds 10%% of period - risk of timing errors!\n");
 } else {
 printf("Clock skew is within acceptable limits.\n");
 }
}

// Compare two processors
void compare_performance(Processor p1, Processor p2) {
 double time1 = calculate_cpu_time_ms(p1.instruction_count, p1.cpi, p1.frequency_hz);
 double time2 = calculate_cpu_time_ms(p2.instruction_count, p2.cpi, p2.frequency_hz);

 printf("\n--- Performance Comparison ---\n");
 printf("Workload: %ld instructions\n\n", p1.instruction_count);

 printf("%s:\n", p1.name);
 printf(" Frequency: %.2f GHz\n", p1.frequency_hz / 1e9);
 printf(" CPI: %.1f\n", p1.cpi);
 printf(" Total Cycles: %.0Lg\n", calculate_total_cycles(p1.instruction_count, p1.cpi));
 printf(" Execution Time: %.4f ms\n\n", time1);

 printf("%s:\n", p2.name);
 printf(" Frequency: %.2f GHz\n", p2.frequency_hz / 1e9);
 printf(" CPI: %.1f\n", p2.cpi);
 printf(" Total Cycles: %.0Lg\n", calculate_total_cycles(p2.instruction_count, p2.cpi));
 printf(" Execution Time: %.4f ms\n\n", time2);

 if (time1 < time2) {
 printf("Result: %s is faster!\n", p1.name);
 printf("Speedup: %.2fx\n", time2 / time1);
 } else if (time2 < time1) {
 printf("Result: %s is faster!\n", p2.name);
 printf("Speedup: %.2fx\n", time1 / time2);
 } else {
 printf("Result: Both processors have equal performance.\n");
 }
}

