import java.util.Scanner;

/**
 * Processor Clock Performance Simulator
 * Demonstrates CPU time calculations and clock synchronization concepts
 */
public class ProcessorClockSimulator {

 // Inner class to represent a processor
 static class Processor {
 String name;
 double clockFrequencyHz; // Clock frequency in Hz
 double cpi; // Cycles per instruction
 long instructionCount; // Number of instructions

 public Processor(String name, double frequencyGHz, double cpi, long instructions) {
 this.name = name;
 this.clockFrequencyHz = frequencyGHz * 1e9; // Convert GHz to Hz
 this.cpi = cpi;
 this.instructionCount = instructions;
 }

 // Calculate clock period in nanoseconds
 public double getClockPeriodNs() {
 return (1.0 / clockFrequencyHz) * 1e9;
 }

 // Calculate total clock cycles needed
 public double getTotalCycles() {
 return instructionCount * cpi;
 }

 // Calculate CPU execution time in milliseconds
 public double getExecutionTimeMs() {
 double clockPeriod = 1.0 / clockFrequencyHz;
 return getTotalCycles() * clockPeriod * 1000.0;
 }
 }

 // Simulate clock tick (rising edge event)
 static class Clock {
 private double frequencyHz;
 private long tickCount;
 private double currentTimeNs;

 public Clock(double frequencyGHz) {
 this.frequencyHz = frequencyGHz * 1e9;
 this.tickCount = 0;
 this.currentTimeNs = 0;
 }

 // Simulate a single clock tick (rising edge)
 public void tick() {
 tickCount++;
 currentTimeNs += (1.0 / frequencyHz) * 1e9;
 }

 public long getTickCount() {
 return tickCount;
 }

 public double getCurrentTimeNs() {
 return currentTimeNs;
 }

 public double getPeriodNs() {
 return (1.0 / frequencyHz) * 1e9;
 }
 }

 public static void main(String[] args) {
 Scanner scanner = new Scanner(System.in);

 System.out.println("========================================");
 System.out.println(" PROCESSOR CLOCK SIMULATOR");
 System.out.println("========================================");

 // Example 1: Basic clock period calculations
 System.out.println("\n--- Clock Period Calculations ---");
 double[] testFrequencies = {1.0, 2.4, 3.2, 4.0, 5.0};
 for (double freq : testFrequencies) {
 double period = (1.0 / (freq * 1e9)) * 1e9;
 System.out.printf("%.1f GHz -> Period: %.3f ns%n", freq, period);
 }

 // Example 2: CPU Time demonstration
 System.out.println("\n--- CPU Time Calculation Demo ---");
 Processor proc = new Processor("Demo Processor", 2.5, 1.5, 500_000_000);
 System.out.println("Processor: " + proc.name);
 System.out.printf("Clock Frequency: %.1f GHz%n", 2.5);
 System.out.printf("Clock Period: %.3f ns%n", proc.getClockPeriodNs());
 System.out.printf("CPI: %.1f%n", proc.cpi);
 System.out.printf("Instruction Count: %d%n", proc.instructionCount);
 System.out.printf("Total Clock Cycles: %.0f%n", proc.getTotalCycles());
 System.out.printf("CPU Execution Time: %.2f ms%n", proc.getExecutionTimeMs());

 // Example 3: Clock synchronization simulation
 System.out.println("\n--- Clock Synchronization (Rising Edge) Demo ---");
 Clock clock = new Clock(3.0); // 3.0 GHz clock
 System.out.printf("Initial: Time = %.3f ns, Ticks = %d%n", 
 clock.getCurrentTimeNs(), clock.getTickCount());

 // Simulate 5 clock cycles
 for (int i = 1; i <= 5; i++) {
 clock.tick();
 System.out.printf("Tick %d: Time = %.3f ns (Rising Edge Event)%n", 
 i, clock.getCurrentTimeNs());
 }

 // Example 4: Compare processors
 System.out.println("\n--- Processor Comparison ---");
 Processor procA = new Processor("Proc-A (High Freq)", 4.0, 2.0, 1_000_000_000);
 Processor procB = new Processor("Proc-B (Efficient)", 3.0, 1.2, 1_000_000_000);

 System.out.println("Workload: 1 billion instructions\n");

 printProcessorStats(procA);
 System.out.println();
 printProcessorStats(procB);

 // Determine winner
 System.out.println("\n--- Result ---");
 if (procA.getExecutionTimeMs() < procB.getExecutionTimeMs()) {
 double speedup = procB.getExecutionTimeMs() / procA.getExecutionTimeMs();
 System.out.printf("%s wins! Speedup: %.2fx%n", procA.name, speedup);
 } else if (procB.getExecutionTimeMs() < procA.getExecutionTimeMs()) {
 double speedup = procA.getExecutionTimeMs() / procB.getExecutionTimeMs();
 System.out.printf("%s wins! Speedup: %.2fx%n", procB.name, speedup);
 } else {
 System.out.println("Both processors have equal performance!");
 }

 // Example 5: Performance equation breakdown
 System.out.println("\n--- CPU Performance Equation ---");
 System.out.println("CPU Time = Instruction Count × CPI × Clock Period");
 demonstratePerformanceEquation(800_000_000, 1.8, 2.8);

 scanner.close();
 }

 static void printProcessorStats(Processor p) {
 System.out.println(p.name + ":");
 System.out.printf(" Frequency: %.1f GHz%n", p.clockFrequencyHz / 1e9);
 System.out.printf(" CPI: %.1f%n", p.cpi);
 System.out.printf(" Execution Time: %.2f ms%n", p.getExecutionTimeMs());
 }

 static void demonstratePerformanceEquation(long instructions, double cpi, double freqGHz) {
 double period = 1.0 / (freqGHz * 1e9);
 double cpuTime = instructions * cpi * period;

 System.out.printf("Given:%n");
 System.out.printf(" Instruction Count = %d%n", instructions);
 System.out.printf(" CPI = %.1f%n", cpi);
 System.out.printf(" Clock Period = %.4f ns%n", period * 1e9);
 System.out.printf("Calculation: %.0f × %.1f × %.4f = %.4f ms%n", 
 instructions, cpi, period * 1e9, cpuTime * 1000);
 }
}
